import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Link, useNavigate, useLocation } from 'react-router-dom';
import { 
  ShieldCheck, 
  Search, 
  LayoutDashboard, 
  Mail, 
  LogIn, 
  UserPlus, 
  LogOut, 
  ChevronDown,
  Github,
  AlertTriangle,
  Zap,
  BarChart3,
  Lock,
  FileJson,
  CheckCircle2,
  Menu,
