                >
                  <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-cyan-500 to-purple-500 flex items-center justify-center text-xs font-bold text-white uppercase">
                    {user.name.charAt(0)}
                  </div>
                  <span className="text-sm font-medium text-white">{user.name}</span>
                  <ChevronDown className="w-4 h-4 text-gray-400" />
                </button>
                {isDropdownOpen && (
                  <div className="absolute right-0 mt-2 w-48 glass-card rounded-2xl py-2 shadow-xl border border-white/10">
                    <Link to="/dashboard/preview" className="block px-4 py-2 text-sm text-gray-300 hover:bg-white/5 hover:text-cyan-400">Dashboard</Link>
                    <button onClick={onLogout} className="w-full text-left block px-4 py-2 text-sm text-red-400 hover:bg-red-500/10">Logout</button>
                  </div>
                )}
              </div>
            ) : (
              <>
                <Link to="/login" className="text-sm font-medium text-gray-300 hover:text-white transition-colors">Login</Link>
                <Link to="/register" className="glass-card px-6 py-2 rounded-full text-sm font-bold text-cyan-400 hover:bg-white/10 transition-all border border-cyan-500/30">
                  Sign Up
                </Link>
              </>
            )}
          </div>

          {/* Mobile menu button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className="p-2 rounded-md text-gray-400 hover:text-white"
            >
              {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden glass-card mx-4 rounded-3xl mt-2 py-4 px-6 absolute left-0 right-0 border border-white/10 animate-in slide-in-from-top-4 duration-300">
          <div className="flex flex-col space-y-4">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsMenuOpen(false)}
                className="text-lg font-medium text-gray-300 hover:text-cyan-400"
              >
                {link.name}
              </Link>
            ))}
            <div className="pt-4 border-t border-white/10 flex flex-col space-y-4">
              {user ? (
                <>
                  <Link to="/dashboard/preview" onClick={() => setIsMenuOpen(false)} className="text-lg font-medium text-cyan-400">Dashboard</Link>
                  <button onClick={() => { onLogout(); setIsMenuOpen(false); }} className="text-lg font-medium text-red-400 text-left">Logout</button>
                </>
              ) : (
                <>
                  <Link to="/login" onClick={() => setIsMenuOpen(false)} className="text-lg font-medium text-gray-300">Login</Link>
                  <Link to="/register" onClick={() => setIsMenuOpen(false)} className="text-lg font-bold text-cyan-400">Sign Up</Link>
                </>
              )}
