import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { UserPlus, Mail, Lock, User as UserIcon, ShieldCheck, ArrowRight } from 'lucide-react';
import { User } from '../App';

interface RegisterProps {
  onRegister: (user: User) => void;
}

const Register: React.FC<RegisterProps> = ({ onRegister }) => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const navigate = useNavigate();

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (password !== confirmPassword) return alert("Passwords don't match");
    const mockUser = { name, email };
    localStorage.setItem('repo_user', JSON.stringify(mockUser));
    onRegister(mockUser);
    navigate('/scan');
  };

  const strength = Math.min(password.length * 10, 100);
  const strengthColor = strength < 40 ? 'bg-red-500' : strength < 80 ? 'bg-yellow-500' : 'bg-green-500';

  return (
    <div className="max-w-md mx-auto px-4 py-20">
      <div className="glass-card p-10 rounded-[2.5rem] border border-white/10 text-center">
        <div className="w-16 h-16 bg-purple-500/20 rounded-2xl flex items-center justify-center mx-auto mb-6">
          <UserPlus className="w-8 h-8 text-purple-400" />
        </div>
        <h2 className="text-3xl font-black text-white mb-2">Create Account</h2>
        <p className="text-gray-400 mb-8">Join the security community</p>

        <form onSubmit={handleRegister} className="space-y-4 text-left">
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-400 ml-4">Full Name</label>
            <div className="relative">
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Lakshmipriya V"
                className="w-full px-6 py-4 rounded-2xl glass-card border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all pl-12"
                required
              />
              <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-400 ml-4">Email Address</label>
            <div className="relative">
              <input 
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="developer@scantinel.io"
                className="w-full px-6 py-4 rounded-2xl glass-card border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all pl-12"
                required
              />
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-400 ml-4">Password</label>
            <div className="relative">
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="w-full px-6 py-4 rounded-2xl glass-card border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all pl-12"
                required
              />
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
            </div>
            <div className="mt-2 h-1 w-full bg-white/5 rounded-full overflow-hidden">
              <div className={`h-full transition-all duration-500 ${strengthColor}`} style={{ width: `${strength}%` }}></div>
            </div>
            <p className="text-[10px] text-gray-500 uppercase tracking-tighter">Security Strength: {strength}%</p>
          </div>
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-400 ml-4">Confirm Password</label>
            <input 
              type="password" 
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full px-6 py-4 rounded-2xl glass-card border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all"
              required
            />
          </div>

          <button 
            type="submit" 
            className="w-full py-4 bg-purple-600 hover:bg-purple-500 text-white font-bold rounded-2xl transition-all shadow-lg flex items-center justify-center group mt-6"
          >
            Get Started <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
          </button>
        </form>

        <p className="mt-8 text-gray-500 text-sm">
          Already have an account? <Link to="/login" className="text-purple-400 hover:underline font-bold">Sign In</Link>
        </p>
      </div>
    </div>
  );
};

export default Register;

