import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Github, Search, CheckCircle2, Loader2, AlertCircle, ArrowRight } from 'lucide-react';

const Scan: React.FC = () => {
  const [url, setUrl] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [step, setStep] = useState(0);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const steps = [
    "Validating repository URL",
    "Cloning remote source code",
    "Building dependency graph",
    "Scanning for static vulnerabilities",
    "Analyzing security patterns",
    "Generating final report"
  ];

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (!url.includes('github.com')) {
      setError('Please enter a valid GitHub repository URL');
      return;
    }
    setError('');
    setIsScanning(true);
  };

  useEffect(() => {
    // Fix: Use ReturnType<typeof setInterval> for better compatibility in browser environment as NodeJS namespace might not be globally available in all configurations
    let interval: ReturnType<typeof setInterval> | null = null;
    if (isScanning && step < steps.length) {
      interval = setInterval(() => {
        setStep(prev => prev + 1);
      }, 1500);
    } else if (isScanning && step === steps.length) {
      setTimeout(() => {
        navigate('/dashboard/current-scan');
      }, 1000);
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isScanning, step, steps.length, navigate]);

  return (
    <div className="max-w-4xl mx-auto px-4 py-20 min-h-[70vh] flex flex-col items-center justify-center">
      {!isScanning ? (
        <div className="w-full text-center space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="inline-block p-4 bg-cyan-500/10 rounded-3xl border border-cyan-500/30 mb-4">
            <Github className="w-16 h-16 text-cyan-400" />
          </div>
          <h1 className="text-5xl font-black text-white">Start Repository Scan</h1>
          <p className="text-gray-400 text-lg max-w-xl mx-auto">
            Paste the public URL of the GitHub repository you want to analyze. RepoScantinel will run a deep-dive security audit.
          </p>

          <form onSubmit={handleScan} className="max-w-2xl mx-auto w-full relative">
            <div className="relative group">
              <input
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="https://github.com/username/repository"
                className="w-full px-8 py-6 rounded-full glass-card border-white/20 text-white text-lg focus:outline-none focus:ring-2 focus:ring-cyan-500 transition-all pl-16 pr-32"
                required
              />
              <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-cyan-400 transition-colors" />
              <button
                type="submit"
                className="absolute right-2 top-2 bottom-2 px-8 bg-cyan-500 hover:bg-cyan-400 text-white font-bold rounded-full transition-all shadow-lg flex items-center group/btn"
              >
                Scan <ArrowRight className="ml-2 w-5 h-5 group-hover/btn:translate-x-1 transition-transform" />
              </button>
            </div>
            {error && (
              <div className="mt-4 flex items-center justify-center text-pink-500 space-x-2">
                <AlertCircle className="w-4 h-4" />
                <span className="text-sm font-medium">{error}</span>
              </div>
            )}
          </form>

          <div className="pt-12 grid grid-cols-2 md:grid-cols-4 gap-4 max-w-2xl mx-auto text-xs font-bold text-gray-500 uppercase tracking-widest">
            <div className="p-3 border border-white/5 rounded-2xl">Python (bandit)</div>
            <div className="p-3 border border-white/5 rounded-2xl">JS/TS (eslint)</div>
            <div className="p-3 border border-white/5 rounded-2xl">Secrets (gitleaks)</div>
            <div className="p-3 border border-white/5 rounded-2xl">Go (gosec)</div>
          </div>
        </div>
      ) : (
        <div className="w-full max-w-lg glass-card p-10 rounded-[2.5rem] border border-white/10 relative overflow-hidden">
          <div className="scan-line"></div>
          <div className="text-center mb-8 relative z-10">
            <div className="relative w-24 h-24 mx-auto mb-6">
              <Loader2 className="w-24 h-24 text-cyan-400 animate-spin absolute inset-0" />
              <div className="absolute inset-0 flex items-center justify-center">
                <span className="text-xs font-bold text-cyan-400">{Math.round((step / steps.length) * 100)}%</span>
              </div>
            </div>
            <h2 className="text-2xl font-bold text-white mb-2">Analyzing Repository</h2>
            <p className="text-gray-400">Please wait while we process the code...</p>
          </div>

          <div className="space-y-4 relative z-10">
            {steps.map((s, i) => (
              <div key={i} className={`flex items-center space-x-3 transition-opacity duration-300 ${i <= step ? 'opacity-100' : 'opacity-20'}`}>
                {i < step ? (
                  <CheckCircle2 className="w-5 h-5 text-green-400" />
                ) : i === step ? (
                  <Loader2 className="w-5 h-5 text-cyan-400 animate-spin" />
                ) : (
                  <div className="w-5 h-5 border-2 border-gray-600 rounded-full"></div>
                )}
                <span className={`text-sm ${i === step ? 'text-white font-bold' : 'text-gray-400'}`}>{s}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Scan;

